        @mcp.tool()
        async def svg_get_document_info(input_filename: str) -> dict:
            """
            Retrieve basic information from an SVG document stored on the server.
        
            IMPORTANT:
            All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') -- no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            Do NOT ask the user to upload a file -- files are pre-placed in the server folder by the user.
            The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the SVG file to inspect, e.g. 'diagram.svg'.
        
            Returns:
                dict: A dictionary containing at minimum:
                    - status: "success" or "error".
                    - message: Human-readable description of the result.
                    - width: Value of the SVG's width attribute (or None if not present).
                    - height: Value of the SVG's height attribute (or None if not present).
                    - viewBox: Value of the SVG's viewBox attribute (or None if not present).
                    - title: Text content of the first <title> element (empty string if none).
                    - element_count: Total number of elements in the SVG document.
        
            Raises:
                FileNotFoundError: If the specified SVG file does not exist.
                RuntimeError: If the current platform is not supported by Aspose.Svg.
        
            Example:
                >>> result = await svg_get_document_info("example.svg")
                >>> result["width"]
                "800"
            """
            # ----------------------------------------------------------------------
            # Resolve and validate the input filename
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path
            import sys
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize the caller-provided name
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
        
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # Aspose.Svg works only on Windows (the .NET runtime requirement)
            if sys.platform != "win32":
                raise RuntimeError("svg_get_document_info is supported only on Windows platforms.")
        
            # ----------------------------------------------------------------------
            # Load the SVG document using Aspose.Svg
            # ----------------------------------------------------------------------
            try:
                from aspose.svg import SVGDocument
        
                with SVGDocument(str(resolved_input)) as document:
                    root = document.document_element
        
                    width = root.get_attribute("width") or None
                    height = root.get_attribute("height") or None
                    view_box = root.get_attribute("viewBox") or None
        
                    title_elements = document.get_elements_by_tag_name("title")
                    title = (
                        title_elements[0].text_content
                        if title_elements.length > 0
                        else ""
                    )
        
                    element_count = len(document.get_elements_by_tag_name("*").to_list())
        
                return {
                    "status": "success",
                    "message": "SVG document information retrieved successfully.",
                    "width": width,
                    "height": height,
                    "viewBox": view_box,
                    "title": title,
                    "element_count": element_count,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Error processing SVG document %s", input_filename)
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def svg_add_element(
            input_filename: str,
            tag: str,
            attributes: dict[str, str],
            output_filename: str | None = None,
        ) -> dict:
            """
            Add a new SVG element to an existing SVG document.
        
            IMPORTANT:
            All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') -- no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            Do NOT ask the user to upload a file -- files are pre-placed in the server folder by the user.
            The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the existing SVG file to modify.
                tag: SVG tag name of the element to add (e.g., "circle", "rect").
                attributes: Dictionary of attribute names and values for the new element.
                output_filename: Optional bare filename for the modified SVG. If omitted, the original file is overwritten.
        
            Returns:
                dict: {"status": "success"|"error", "message": str, "output_filename": str}
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                ValueError: If the tag name is empty or attribute handling fails.
                NotImplementedError: If the platform is not Windows.
        
            Example:
                await svg_add_element(
                    input_filename="diagram.svg",
                    tag="circle",
                    attributes={"cx": "50", "cy": "50", "r": "40", "fill": "red"},
                    output_filename="diagram_modified.svg",
                )
            """
            # -------------------------------------------------------------------------
            # Imports and basic validation (must be before any Aspose import)
            # -------------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
            import sys
        
            logger = logging.getLogger(__name__)
        
            # Platform check
            if not sys.platform.startswith("win"):
                raise NotImplementedError("svg_add_element is only supported on Windows platforms.")
        
            # -------------------------------------------------
            # Resolve and validate the input SVG file
            # -------------------------------------------------
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # -------------------------------------------------
            # Resolve the output location
            # -------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # Overwrite the original file
                output_filename = input_filename
                resolved_output = resolved_input
        
            # Ensure the output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # -------------------------------------------------------------------------
            # Aspose.Svg operations (import after validation)
            # -------------------------------------------------------------------------
            from aspose.svg import SVGDocument
        
            try:
                with SVGDocument(str(resolved_input)) as document:
                    # Create the new element in the SVG namespace
                    ns = "http://www.w3.org/2000/svg"
                    element = document.create_element_ns(ns, tag)
                    if element is None:
                        raise ValueError(f"Unable to create element for tag '{tag}'.")
        
                    # Apply provided attributes
                    for attr_name, attr_value in attributes.items():
                        element.set_attribute(attr_name, attr_value)
        
                    # Append the new element to the root <svg> element
                    document.document_element.append_child(element)
        
                    # Save the modified document
                    document.save(str(resolved_output))
        
            except Exception as exc:  # pylint: disable=broad-except
                logger.exception("Failed to add element to SVG")
                return {"status": "error", "message": str(exc), "output_filename": output_filename}
        
            return {
                "status": "success",
                "message": f"Element '{tag}' added successfully.",
                "output_filename": output_filename,
            }

        @mcp.tool()
        async def svg_query_elements(
            input_filename: str,
            css_selector: str,
        ) -> dict:
            """
            Query SVG elements using a CSS selector.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.svg') -- no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file -- files are pre-placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the SVG file to query. Must exist in ASPOSE_FILES_PATH.
                css_selector: CSS selector string (e.g., "rect.red").
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "elements": list[dict]   # present only on success
                }
                Each element dict contains:
                    "tag_name": str,
                    "attributes": dict,
                    "text_content": str
        
            Raises:
                FileNotFoundError: If the specified SVG file does not exist.
                Exception: Propagates unexpected errors as an error-status dict.
        
            Example:
                result = await svg_query_elements("diagram.svg", "circle.highlight")
                # result["elements"] -> [{'tag_name': 'circle', 'attributes': {'fill': 'red'}, 'text_content': ''}, ...]
            """
            import sys
            if sys.platform != "win32":
                raise RuntimeError("Aspose.Svg is only supported on Windows platforms.")

            # ----------------------------------------------------------------------
            # Resolve and validate the input file (must be a bare filename)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize filename
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
        
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Lazy import of Aspose.Svg
            # ----------------------------------------------------------------------
            try:
                from aspose.svg import SVGDocument
            except Exception as exc:
                logger.error("Failed to import Aspose.Svg: %s", exc)
                return {"status": "error", "message": f"Import error: {exc}"}
        
            # ----------------------------------------------------------------------
            # Perform the query
            # ----------------------------------------------------------------------
            try:
                with SVGDocument(str(resolved_input)) as document:
                    elements = document.query_selector_all(css_selector)
        
                if not elements:
                    return {
                        "status": "success",
                        "message": "No matching elements found.",
                        "elements": [],
                    }
        
                result_elements = []
                for el in elements:
                    # tag name
                    tag_name = getattr(el, "tag_name", "")
        
                    # attributes - try to obtain attribute names if the API provides it
                    attr_names = []
                    if hasattr(el, "get_attribute_names"):
                        try:
                            attr_names = list(el.get_attribute_names())
                        except Exception:
                            pass
        
                    attributes = {}
                    for name in attr_names:
                        try:
                            attributes[name] = el.get_attribute(name)
                        except Exception:
                            attributes[name] = None
        
                    # text content
                    text_content = getattr(el, "text_content", "")
        
                    result_elements.append(
                        {
                            "tag_name": tag_name,
                            "attributes": attributes,
                            "text_content": text_content,
                        }
                    )
        
                return {
                    "status": "success",
                    "message": f"Found {len(result_elements)} element(s).",
                    "elements": result_elements,
                }
        
            except Exception as exc:  # catch Aspose or selector errors
                logger.exception("Error querying SVG elements")
                return {"status": "error", "message": str(exc)}

